#![allow(clippy::unwrap_used, clippy::expect_used, clippy::doc_markdown)]

use mqo_eval::{
    summary::summarize,
    types::{QuestionResult, Verdict},
};

fn make_result(id: &str, verdict: Verdict, confidence: f64, latency_ms: u64) -> QuestionResult {
    QuestionResult {
        question: format!("Q{id}"),
        id: id.to_owned(),
        verdict,
        confidence,
        pillars_fired: vec![],
        latency_ms,
    }
}

#[test]
fn acceptance_ac4() {
    // Known fixture: 3 correct, 1 wrong, 1 no_bind.
    let results = vec![
        make_result("q1", Verdict::Correct, 0.9, 100),
        make_result("q2", Verdict::Correct, 0.8, 200),
        make_result("q3", Verdict::Correct, 0.7, 300),
        make_result("q4", Verdict::Wrong, 0.3, 50),
        make_result("q5", Verdict::NoBind, 0.0, 10),
    ];

    let stats = summarize(&results);

    assert_eq!(stats.total, 5, "total must be 5");
    assert_eq!(stats.correct, 3);
    assert_eq!(stats.wrong, 1);
    assert_eq!(stats.no_bind, 1);

    // accuracy = 3/5 = 0.6
    assert!(
        (stats.accuracy - 0.6).abs() < 1e-9,
        "accuracy should be 0.6, got {}",
        stats.accuracy
    );

    // no_bind_rate = 1/5 = 0.2
    assert!(
        (stats.no_bind_rate - 0.2).abs() < 1e-9,
        "no_bind_rate should be 0.2, got {}",
        stats.no_bind_rate
    );

    // mean_confidence = (0.9+0.8+0.7+0.3+0.0)/5 = 0.54
    assert!(
        (stats.mean_confidence - 0.54).abs() < 1e-9,
        "mean_confidence should be 0.54, got {}",
        stats.mean_confidence
    );

    // mean_latency_ms = (100+200+300+50+10)/5 = 132
    assert!(
        (stats.mean_latency_ms - 132.0).abs() < 1e-9,
        "mean_latency_ms should be 132, got {}",
        stats.mean_latency_ms
    );
}
